const posts = $input.all().map(item => item.json);
return {
  json: { posts: posts }
};

const posts = $json.posts;
const titles = posts.map(p => p.title).join('\n- ');
const contentStr = posts.map(p => `TÍTULO: ${p.title}\nRESUMO: ${p.summary}`).join('\n\n');

return {
  world: 'SPORTS',
  posts: posts,
  titles_list: titles,
  content_to_read: contentStr
};

// 1. Navegar até onde a IA REALMENTE escondeu o texto
let aiText = "";
if ($json.output && Array.isArray($json.output) && $json.output[0] && $json.output[0].content) {
  aiText = $json.output[0].content[0].text || "";
} else {
  aiText = $json.text || $json.content || "";
}

// 2. Extrair o bloco JSON da resposta
let parsed = {};
try {
  const match = aiText.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  }
} catch(e) {}

const posts = $('Formatar Posts p/ IA').item.json.posts;

// Agrupar posts por categoria
const categoriesMap = {};
posts.forEach(post => {
  const catName = (post.sub_category || post.category || "GERAL").toUpperCase();
  if (!categoriesMap[catName]) categoriesMap[catName] = [];

  let themeObj = {};
  try {
     themeObj = typeof post.theme_config === 'string' ? JSON.parse(post.theme_config) : post.theme_config;
  } catch(e){}

  categoriesMap[catName].push({
    headline: post.title,
    story: post.summary,
    link: post.url,
    theme: themeObj || {}
  });
});

const categoriesList = Object.keys(categoriesMap).map(key => {
  return { name: key, items: categoriesMap[key] };
});

const contentJson = {
  title: parsed.title || "Fresh News Edição",
  intro: parsed.intro || "Sem resumo disponível.",
  quickTakes: parsed.quickTakes || [],
  categories: categoriesList,
  image_prompt: ""
};

return {
  title: parsed.title || "Fresh News Edição",
  intro: parsed.intro || "",
  whatsapp_greeting: parsed.whatsapp_greeting || "",
  whatsapp_farewell: parsed.whatsapp_farewell || "",
  world: $('Formatar Posts p/ IA').item.json.world,
  content_json: contentJson,
  post_ids: posts.map(p => p.id)
};
